// Get all terms for a specific difficulty
export function getTermsByDifficulty(difficulty) {
  if (!difficulty) return SLANG_TERMS
  return SLANG_TERMS.filter(t => t.difficulty === difficulty)
}

export function getTermsByCategory(category) {
  if (!category) return SLANG_TERMS
  return SLANG_TERMS.filter(t => t.category === category)
}

